The issue here is that you're mixing **top-level statements** with a namespace or type declarations in your code. Top-level statements, introduced in C# 9, allow you to write code without explicitly defining a `Main` method, but **they must come before any namespace or type declaration**.

Here's how to fix your code and get it running:

### Updated Code

```csharp
// Aigo pattern recognition, KNN & Levenshtein Distance

using System;
using System.Collections.Generic;
using System.Linq;

public class PatternMatcher
{
    private readonly Dictionary<string, int> patternDictionary = new();

    // Adds input to the dictionary
    public void Learn(string input)
    {
        if (patternDictionary.ContainsKey(input))
            patternDictionary[input]++;
        else
            patternDictionary[input] = 1;
    }

    // Matches a query with confidence
    public string Match(string query)
    {
        if (!patternDictionary.Any())
            return "dontKnow";

        var bestMatch = patternDictionary
            .Select(p => new
            {
                Pattern = p.Key,
                Distance = LevenshteinDistance(query, p.Key),
                Frequency = p.Value
            })
            .OrderBy(x => x.Distance)
            .First();

        double confidence = 1.0 / (1 + bestMatch.Distance);

        return confidence > 0.5 ? $"{bestMatch.Pattern} (Confidence: {confidence:P2})" : "dontKnow";
    }

    public static int LevenshteinDistance(string s1, string s2)
    {
        int m = s1.Length;
        int n = s2.Length;
        if (m == 0) return n;
        if (n == 0) return m;

        var v_0 = new int[n + 1];
        var v_1 = new int[n + 1];
        int costDelete = 0;
        int costInsert = 0;
        int costSub = 0;

        for (var i = 0; i <= n; i++)
        {
            v_0[i] = i;
        }

        for (var i = 0; i < m; i++)
        {
            v_1[0] = i + 1;
            for (var j = 0; j < n; j++)
            {
                costDelete = v_0[j + 1] + 1;
                costInsert = v_1[j] + 1;
                costSub = (s1[i] == s2[j]) ? v_0[j] : v_0[j] + 1;
                v_1[j + 1] = Math.Min(costDelete, Math.Min(costInsert, costSub));
            }
            (v_0, v_1) = (v_1, v_0);
        }
        return v_0[n];
    }
}

class Program
{
    static void Main(string[] args)
    {
        // Initialize PatternMatcher
        var aigo = new PatternMatcher();

        // Example: Learning patterns
        aigo.Learn("hello");
        aigo.Learn("world");
        aigo.Learn("hello");

        // Example: Matching a query
        string result = aigo.Match("helo");
        Console.WriteLine($"Matched Pattern: {result}");

        // Example: Calculating Levenshtein Distance directly
        int distance = PatternMatcher.LevenshteinDistance("hello", "helo");
        Console.WriteLine($"Levenshtein Distance: {distance}");
    }
}
```

---

### Key Changes
1. **Removed Top-Level Statements**:
   - The `var Aigo = new PatternMatcher.Main();` line was removed because top-level statements cannot coexist with the `Main` method in your `Program` class.

2. **Added a Proper `Main` Method**:
   - Encapsulated all the logic inside the `Main` method in the `Program` class.

3. **Corrected Syntax for Loops**:
   - Updated the loops in `LevenshteinDistance` to ensure they run correctly.

4. **Encapsulation**:
   - Ensured `PatternMatcher` methods can be used cleanly by creating an instance of the class.

---

