# Implementing the Levenshtein Distance function in Python based on the provided C# algorithm

def levenshtein_distance(s1, s2):
    m, n = len(s1), len(s2)
    if m == 0:
        return n
    if n == 0:
        return m

    v_0 = list(range(n + 1))  # Initialize the first row
    v_1 = [0] * (n + 1)       # Initialize the second row

    for i in range(m):
        v_1[0] = i + 1  # First column of the current row
        for j in range(n):
            cost_delete = v_0[j + 1] + 1
            cost_insert = v_1[j] + 1
            cost_sub = v_0[j] if s1[i] == s2[j] else v_0[j] + 1
            v_1[j + 1] = min(cost_delete, cost_insert, cost_sub)
        v_0, v_1 = v_1, v_0  # Swap rows

    return v_0[n]

