### **2. Inverted Index Implementation in C#**
An **inverted index** maps words or substrings to patterns for fast lookups.

#### Inverted Index Class
```csharp
using System;
using System.Collections.Generic;
using System.Linq;

class InvertedIndex
{
    private readonly Dictionary<string, List<string>> index = new();

    public void Build(IEnumerable<string> patterns)
    {
        foreach (var pattern in patterns)
        {
            foreach (var word in Tokenize(pattern))
            {
                if (!index.ContainsKey(word))
                    index[word] = new List<string>();
                index[word].Add(pattern);
            }
        }
    }

    public IEnumerable<string> Search(string prompt)
    {
        var candidates = new HashSet<string>();
        foreach (var word in Tokenize(prompt))
        {
            if (index.ContainsKey(word))
                candidates.UnionWith(index[word]);
        }
        return candidates;
    }

    private static IEnumerable<string> Tokenize(string text)
    {
        return text.ToLower().Split(new[] { ' ', '.', ',', ';', '!' }, StringSplitOptions.RemoveEmptyEntries);
    }
}
```

#### Usage
```csharp
class Program
{
    static void Main()
    {
        // Example Patterns
        var patterns = new[] {
            "the early bird catches the worm",
            "actions speak louder than words do",
            "a picture is worth a thousand words"
        };

        // Build the Inverted Index
        var index = new InvertedIndex();
        index.Build(patterns);

        // Search with a prompt
        string prompt = "actions";
        var candidates = index.Search(prompt);

        // Compute Levenshtein distance for each candidate
        Console.WriteLine("Inverted Index Matches:");
        foreach (var candidate in candidates)
        {
            int distance = LevenshteinDistance(prompt, candidate);
            Console.WriteLine($"Pattern: {candidate}, Distance: {distance}");
        }
    }

    // Levenshtein Distance Function
    static int LevenshteinDistance(string s1, string s2)
    {
        int m = s1.Length, n = s2.Length;
        if (m == 0) return n;
        if (n == 0) return m;

        var v0 = new int[n + 1];
        var v1 = new int[n + 1];

        for (int i = 0; i <= n; i++) v0[i] = i;

        for (int i = 0; i < m; i++)
        {
            v1[0] = i + 1;
            for (int j = 0; j < n; j++)
            {
                int costDelete = v0[j + 1] + 1;
                int costInsert = v1[j] + 1;
                int costSub = (s1[i] == s2[j]) ? v0[j] : v0[j] + 1;
                v1[j + 1] = Math.Min(Math.Min(costDelete, costInsert), costSub);
            }
            Array.Copy(v1, v0, v1.Length);
        }
        return v0[n];
    }
}
```

