    public IEnumerable<string> Search(string prompt, int maxN, int maxDistance)
    {
        var candidates = new HashSet<string>();
        foreach (var ngram in GenerateNGrams(prompt, maxN))
        {
            // Exact matches
            if (index.ContainsKey(ngram))
                candidates.UnionWith(index[ngram]);

            // Fuzzy matches
            foreach (var entry in index)
            {
                if (LevenshteinDistance(ngram, entry.Key) <= maxDistance)
                    candidates.UnionWith(entry.Value);
            }
        }
        return candidates;
    }

    private IEnumerable<string> GenerateNGrams(string input, int maxN)
    {
        var ngrams = new List<string>();
        for (int n = 1; n <= maxN; n++)
        {
            for (int i = 0; i <= input.Length - n; i++)
            {
                ngrams.Add(input.Substring(i, n));
            }
        }
        return ngrams;
    }

    private int LevenshteinDistance(string s1, string s2)
    {
        int m = s1.Length, n = s2.Length;
        if (m == 0) return n;
        if (n == 0) return m;

        var v0 = new int[n + 1];
        var v1 = new int[n + 1];

        for (int i = 0; i <= n; i++) v0[i] = i;

        for (int i = 0; i < m; i++)
        {
            v1[0] = i + 1;
            for (int j = 0; j < n; j++)
            {
                int costDelete = v0[j + 1] + 1;
                int costInsert = v1[j] + 1;
                int costSub = (s1[i] == s2[j]) ? v0[j] : v0[j] + 1;
                v1[j + 1] = Math.Min(Math.Min(costDelete, costInsert), costSub);
            }
            Array.Copy(v1, v0, v1.Length);
        }
        return v0[n];
    }
}
