### **3. Trie Optimization for Dynamic Fuzzy Matching**

Instead of iterating through all indexed n-grams, store them in a **trie** to dynamically compute matches. This avoids comparing the prompt n-grams to all entries.

#### Example: Trie-Based Dynamic Matching
```csharp
class TrieNode
{
    public Dictionary<char, TrieNode> Children { get; set; } = new();
    public List<string> Patterns { get; set; } = new();
}

class Trie
{
    private readonly TrieNode root = new();

    public void Insert(string ngram, string pattern)
    {
        var node = root;
        foreach (char c in ngram)
        {
            if (!node.Children.ContainsKey(c))
                node.Children[c] = new TrieNode();
            node = node.Children[c];
        }
        node.Patterns.Add(pattern);
    }

    public void FuzzySearch(string ngram, int maxDistance, List<string> results, Func<string, string, int> distanceFunc)
    {
        void SearchNode(TrieNode node, string prefix, int depth, int distance)
        {
            if (distance > maxDistance) return;

            if (depth == ngram.Length)
            {
                results.AddRange(node.Patterns);
                return;
            }

            foreach (var child in node.Children)
            {
                SearchNode(child.Value, prefix + child.Key, depth + 1, 
                    distance + (child.Key == ngram[depth] ? 0 : 1));
            }
        }

        SearchNode(root, "", 0, 0);
    }
}
```

