using System;
using System.Collections.Generic;

class NGramGenerator
{
    public static IEnumerable<string> GenerateCharacterNGrams(string input, IEnumerable<int> charLengths)
    {
        var ngrams = new List<string>();
        foreach (var n in charLengths)
        {
            for (int i = 0; i <= input.Length - n; i++)
            {
                ngrams.Add(input.Substring(i, n));
            }
        }
        return ngrams;
    }

    public static IEnumerable<string> GenerateWordNGrams(string input, IEnumerable<int> wordLengths)
    {
        var words = input.Split(new[] { ' ', '\t', '\n' }, StringSplitOptions.RemoveEmptyEntries);
        var ngrams = new List<string>();
        foreach (var n in wordLengths)
        {
            for (int i = 0; i <= words.Length - n; i++)
            {
                ngrams.Add(string.Join(" ", words[i..(i + n)]));
            }
        }
        return ngrams;
    }

    public static IEnumerable<string> GenerateMixedNGrams(string input, IEnumerable<int> charLengths, IEnumerable<int> wordLengths)
    {
        var mixedNGrams = new List<string>();
        mixedNGrams.AddRange(GenerateCharacterNGrams(input, charLengths));
        mixedNGrams.AddRange(GenerateWordNGrams(input, wordLengths));
        return mixedNGrams;
    }
}
```

