class InvertedIndex
{
    private readonly Dictionary<string, List<string>> index = new();

    public void Build(IEnumerable<string> patterns)
    {
        foreach (var pattern in patterns)
        {
            var ngrams = NGramGenerator.GenerateAdaptiveNGrams(pattern);
            foreach (var ngram in ngrams)
            {
                if (!index.ContainsKey(ngram))
                    index[ngram] = new List<string>();
                index[ngram].Add(pattern);
            }
        }
    }

    public IEnumerable<string> Search(string prompt)
    {
        var candidates = new HashSet<string>();
        var ngrams = NGramGenerator.GenerateAdaptiveNGrams(prompt);

        foreach (var ngram in ngrams)
        {
            if (index.ContainsKey(ngram))
                candidates.UnionWith(index[ngram]);
        }

        return candidates;
    }
}
```

