```csharp
class Program
{
    static void Main()
    {
        string prompt = "actions speak louder than words";
        string pattern = "actions speak louder";

        var score = NGramScorer.Score(prompt, pattern);

        Console.WriteLine($"Score: {score}");
    }
}
```

