    public static IEnumerable<string> GenerateCharNGramsForWords(string input, IEnumerable<int> charLengths)
    {
        var sanitizedInput = Sanitizer.SanitizeInput(input);
        var words = sanitizedInput.Split(new[] { ' ' }, StringSplitOptions.RemoveEmptyEntries);

        var ngrams = new List<string>();
        foreach (var word in words)
        {
            foreach (var n in charLengths)
            {
                for (int i = 0; i <= word.Length - n; i++)
                {
                    ngrams.Add(word.Substring(i, n));
                }
            }
        }
        return ngrams;
    }

    // Generate word-level n-grams for full phrases
    public static IEnumerable<string> GenerateWordNGrams(string input, IEnumerable<int> wordLengths)
    {
        var sanitizedInput = Sanitizer.SanitizeInput(input);
        var words = sanitizedInput.Split(new[] { ' ' }, StringSplitOptions.RemoveEmptyEntries);

        var ngrams = new List<string>();
        foreach (var n in wordLengths)
        {
            for (int i = 0; i <= words.Length - n; i++)
            {
                ngrams.Add(string.Join(" ", words[i..(i + n)]));
            }
        }
        return ngrams;
    }

    // Combine both char-level (word) and word-level n-grams
    public static IEnumerable<string> GenerateAdaptiveNGrams(string input)
    {
        var charLengths = new[] { 1, 3 }; // 1-char and 3-char n-grams
        var wordLengths = new[] { 1, 2 }; // 1-word and 2-word n-grams

        var ngrams = new List<string>();

        // Character n-grams limited to individual words
        ngrams.AddRange(GenerateCharNGramsForWords(input, charLengths));

        // Word-level n-grams for full phrases
        ngrams.AddRange(GenerateWordNGrams(input, wordLengths));

        return ngrams;
    }
}
