                foreach (var word in patternWords)
                {
                    if (!matchedWords.Contains(word)) // Avoid duplicates
                        matchedWords.Add(word);
                }
            }
        }
    }

    // Step 2: Word-level sequence matching
    if (!matchedWords.Any())
        return Enumerable.Empty<(string candidate, double normalizedScore)>(); // No matches

    var matchedWordNGrams = NGramGenerator.GenerateWordNGrams(string.Join(" ", matchedWords));
    var scorer = new NGramScorer();
