### **Updated `NGramScorer` Implementation**

```csharp
class NGramScorer
{
    public (int Max, int Actual) ComputeScore(IEnumerable<string> promptWords, IEnumerable<string> patternWords)
    {
        int maxScore = 0, actualScore = 0;

        // Step 1: Char-by-Char Scoring for Words
        foreach (var promptWord in promptWords)
        {
            int wordMaxScore = 0, wordActualScore = 0;

            foreach (var patternWord in patternWords)
            {
                var charScore = ComputeCharFuzzyScore(promptWord, patternWord);
                wordMaxScore = Math.Max(wordMaxScore, charScore.max);
                wordActualScore = Math.Max(wordActualScore, charScore.actual);
            }

            // Aggregate word-level scores
            maxScore += wordMaxScore;
            actualScore += wordActualScore;
        }

        // Step 2: Word-Level N-Gram Scoring
        var promptWordNGrams = GenerateWordNGrams(promptWords);
        var patternWordNGrams = GenerateWordNGrams(patternWords);

        foreach (var promptNGram in promptWordNGrams)
        {
            if (patternWordNGrams.Contains(promptNGram))
            {
                // Exact match
                int nGramScore = promptNGram.Length; // Add points based on the length of the n-gram
                maxScore += nGramScore;
                actualScore += nGramScore;
            }
            else
            {
                // Mismatch penalty
                int mismatchPenalty = promptNGram.Length;
                maxScore += mismatchPenalty;
                actualScore -= mismatchPenalty;
            }
        }

        return (maxScore, Math.Max(0, actualScore)); // Ensure non-negative score
    }

    private (int max, int actual) ComputeCharFuzzyScore(string promptWord, string patternWord)
    {
        int maxScore = promptWord.Length; // Perfect match is the length of the prompt word
        int actualScore = 0;

        int minLength = Math.Min(promptWord.Length, patternWord.Length);
        int mismatchCount = 0;

        for (int i = 0; i < minLength; i++)
        {
            if (promptWord[i] == patternWord[i])
                actualScore++;
            else
                mismatchCount++;
        }

        // Account for extra characters in either word
        mismatchCount += Math.Abs(promptWord.Length - patternWord.Length);
        actualScore -= mismatchCount; // Deduct points for mismatches

        return (maxScore, Math.Max(0, actualScore)); // Ensure non-negative score
    }

    private IEnumerable<string> GenerateWordNGrams(IEnumerable<string> words)
    {
        var wordList = words.ToList();
        var nGrams = new List<string>();

        for (int n = 1; n <= 2; n++) // Generate 1-word and 2-word n-grams
        {
            for (int i = 0; i <= wordList.Count - n; i++)
            {
                nGrams.Add(string.Join(" ", wordList.Skip(i).Take(n)));
            }
        }

        return nGrams;
    }
}
