private (int max, int actual) ComputeCharFuzzyScore(string promptWord, string patternWord)
{
    int maxScore = patternWord.Length; // Max score is the length of the pattern word
    int actualScore = 0;

    int minLength = Math.Min(promptWord.Length, patternWord.Length);
    for (int i = 0; i < minLength; i++)
    {
        if (promptWord[i] == patternWord[i])
            actualScore++;
    }

    // Add remaining mismatched characters as penalty
    int lengthDelta = Math.Abs(promptWord.Length - patternWord.Length);
    actualScore -= lengthDelta;

    return (maxScore, Math.Max(0, actualScore)); // Ensure non-negative score
}
