    // Step 1: Generate word-level n-grams from the prompt
    var wordGrams = NGramGenerator.GenerateWordNGrams(sanitizedPrompt);
    var matchedPatterns = new HashSet<string>();

    // Step 2: Match word-level n-grams directly using wordTokenStore
    foreach (var wGram in wordGrams)
    {
        if (wordTokenStore.ContainsKey(wGram))
        {
            // Add all patterns containing this word n-gram
            foreach (var pattern in wordTokenStore[wGram])
            {
                matchedPatterns.Add(pattern);
            }
        }
    }

    // Step 3: Fuzzy matching for unmatched word n-grams
    var unmatchedWordGrams = wordGrams.Where(wGram => !wordTokenStore.ContainsKey(wGram));
    foreach (var wGram in unmatchedWordGrams)
    {
        // Generate char-level n-grams for the unmatched word n-gram
        var charGrams = NGramGenerator.GenerateCharNGrams(new List<string> { wGram });

        // Use charTokenStore to find candidate word n-grams
        var candidateWordGrams = new HashSet<string>();
        foreach (var charGram in charGrams)
