            {
                foreach (var candidateWord in charTokenStore[charGram])
                {
                    candidateWordGrams.Add(candidateWord);
                }
            }
        }

        // Resolve candidate word n-grams to their associated patterns
        foreach (var candidateWord in candidateWordGrams)
        {
            if (wordTokenStore.ContainsKey(candidateWord))
            {
                foreach (var pattern in wordTokenStore[candidateWord])
                {
                    matchedPatterns.Add(pattern);
                }
            }
        }
    }

    // Step 4: Return matched patterns as candidates (scoring omitted for simplicity)
    return matchedPatterns.Select(pattern => (candidate: pattern, normalizedScore: 1.0));
}
